pub fn syscall(syscall_id: usize, args: [usize; 6]) -> isize {
    match syscall_id {
        SYSCALL_GETCWD => sys_getcwd(args[0] as *mut u8, args[1] as usize),
        SYSCALL_DUP => sys_dup(args[0]),
        SYSCALL_DUP3 => sys_dup3(args[0] as usize, args[1] as usize),
        SYSCALL_MKDIRAT => sys_mkdirat(args[0] as isize, args[1] as *const u8, args[2] as u32),
        SYSCALL_UNLINKAT => sys_unlinkat(args[0] as isize, args[1] as *const u8, args[2] as u32),
        SYSCALL_UMOUNT2 => sys_umount(args[0] as *const u8, args[1] as usize),
        SYSCALL_MOUNT => sys_mount(
            args[0] as *const u8,
            args[1] as *const u8,
            args[2] as *const u8,
            args[3] as usize,
            args[4] as *const u8,
        ),
        SYSCALL_CHDIR => sys_chdir(args[0] as *const u8),
        SYSCALL_OPENAT => sys_openat(
            args[0] as isize,
            args[1] as *const u8,
            args[2] as u32,
            args[3] as u32,
        ),
        SYSCALL_CLOSE => sys_close(args[0]),
        SYSCALL_PIPE => sys_pipe2(args[0] as *mut u32),
        SYSCALL_GETDENTS64 => {
            sys_getdents64(args[0] as usize, args[1] as *const u8, args[2] as usize)
        }
        SYSCALL_READ => sys_read(args[0], args[1] as *const u8, args[2]),
        SYSCALL_WRITE => sys_write(args[0], args[1] as *const u8, args[2]),
        SYSCALL_FSTAT => sys_fstat(args[0] as usize, args[1] as *const u8),
        SYSCALL_EXIT => sys_exit(args[0] as i32),
        SYSCALL_NANOSLEEP => sys_nanosleep(args[0] as *mut Timespec, args[1] as *mut Timespec),
        SYSCALL_YIELD => sys_yield(),
        SYSCALL_KILL => sys_kill(args[0], args[1] as i32),
        SYSCALL_SIGACTION => sys_sigaction(
            args[0] as i32,
            args[1] as *const SignalAction,
            args[2] as *mut SignalAction,
        ),
        SYSCALL_SIGPROCMASK => sys_sigprocmask(args[0] as u32),
        SYSCALL_SIGRETURN => sys_sigretrun(),
        SYSCALL_TIMES => sys_times(args[0] as *mut Tms),
        SYSCALL_UNAME => sys_uname(args[0] as *mut Utsname),
        SYSCALL_GET_TIME_OF_DAY => sys_get_time_of_day(args[0] as *mut Timespec),
        SYSCALL_BRK => sys_brk(args[0]),
        SYSCALL_GETPID => sys_getpid(),
        SYSCALL_GETPPID => sys_getppid(),
        SYSCALL_CLONE => sys_fork(args[0] as usize, args[1] as usize),
        SYSCALL_EXEC => sys_exec(args[0] as *const u8, args[1] as *const usize),
        SYSCALL_WAIT4 => sys_wait4(args[0] as isize, args[1] as *mut i32, args[2] as usize),
        SYSCALL_MMAP => sys_mmap(
            args[0] as usize,
            args[1] as usize,
            args[2] as u32,
            args[3] as u32,
            args[4] as usize,
            args[5] as usize,
        ),
        SYSCALL_MUNMAP => sys_munmap(args[0] as usize, args[1] as usize),
        SYSCALL_SHUTDOWN => shutdown(),
        _ => panic!("Unsupported syscall_id: {}", syscall_id),
    }
}

use crate::fs::{
    make_pipe, mkdir_at, open_file_at, remove_from_file_table, FileClass, Kstat, OpenFlags,
    AT_FDCWD, unlinkat,
};
use crate::mm::{translated_byte_buffer, translated_refmut, translated_str, UserBuffer};
use crate::task::{current_task, current_user_token};

pub fn sys_write(fd: usize, buf: *const u8, len: usize) -> isize {
    let token = current_user_token();
    let task = current_task().unwrap();
    let inner = task.inner_exclusive_access();
    if fd >= inner.fd_table.len() {
        return -1;
    }
    if let Some(file) = &inner.fd_table[fd] {
        let file = match file {
            FileClass::OSInode(f) => f.clone(),
            FileClass::Other(f) => f.clone(),
        };
        if !file.writable() {
            return -1;
        }
        // release current task TCB manually to avoid multi-borrow
        drop(inner);
        file.write(UserBuffer::new(translated_byte_buffer(token, buf, len))) as isize
    } else {
        -1
    }
}

pub fn sys_read(fd: usize, buf: *const u8, len: usize) -> isize {
    let token = current_user_token();
    let task = current_task().unwrap();
    let inner = task.inner_exclusive_access();
    if fd >= inner.fd_table.len() {
        return -1;
    }
    if let Some(fileclass) = &inner.fd_table[fd] {
        let file = match fileclass {
            FileClass::OSInode(f) => f.clone(),
            FileClass::Other(f) => f.clone(),
        };
        // release current task TCB manually to avoid multi-borrow
        drop(inner);
        if !file.readable() {
            return -1;
        }
        file.read(UserBuffer::new(translated_byte_buffer(token, buf, len))) as isize
    } else {
        -1
    }
}

pub fn sys_openat(fd: isize, path: *const u8, flags: u32, _mode: u32) -> isize {
    let token = current_user_token();
    let path = translated_str(token, path);
    if let Some(inode) = open_file_at(fd, path.as_str(), OpenFlags::from_bits(flags).unwrap()) {
        let task = current_task().unwrap();
        let mut inner = task.inner_exclusive_access();
        let fd = inner.alloc_fd();
        inner.fd_table[fd] = Some(FileClass::OSInode(inode));
        fd as isize
    } else {
        -1
    }
}

pub fn sys_mkdirat(dirfd: isize, path: *const u8, _mode: u32) -> isize {
    let token = current_user_token();
    let path = translated_str(token, path);
    mkdir_at(dirfd, path.as_str())
}

pub fn sys_chdir(path: *const u8) -> isize {
    let token = current_user_token();
    let path = translated_str(token, path);

    // 在 open_file_at 中会用到当前进程变量，因此会获得锁，
    // 如果把这段放后面会死锁
    let new_cwd = open_file_at(AT_FDCWD, &path, OpenFlags::RDWR).unwrap();

    let task = current_task().unwrap();
    let mut inner = task.inner_exclusive_access();
    inner.cwd = new_cwd;
    remove_from_file_table();
    0
}

pub fn sys_close(fd: usize) -> isize {
    let task = current_task().unwrap();
    let mut inner = task.inner_exclusive_access();
    if fd >= inner.fd_table.len() {
        return -1;
    }
    if inner.fd_table[fd].is_none() {
        return -1;
    }
    inner.fd_table[fd].take();
    remove_from_file_table();
    0
}

pub fn sys_getdents64(fd: usize, buf: *const u8, len: usize) -> isize {
    let token = current_user_token();
    let mut buf = UserBuffer::new(translated_byte_buffer(token, buf, len));
    let task = current_task().unwrap();
    let inner = task.inner_exclusive_access();
    if fd >= inner.fd_table.len() {
        return -1;
    }
    if let Some(file) = &inner.fd_table[fd] {
        match file {
            FileClass::OSInode(inode) => {
                return buf.read(inode.getdents64().as_bytes()) as isize;
            }
            _ => return -1,
        }
    } else {
        return -1;
    }
}

pub fn sys_fstat(fd: usize, buf: *const u8) -> isize {
    let token = current_user_token();
    let mut buf = UserBuffer::new(translated_byte_buffer(
        token,
        buf,
        core::mem::size_of::<Kstat>(),
    ));
    let task = current_task().unwrap();
    let inner = task.inner_exclusive_access();
    if fd >= inner.fd_table.len() {
        return -1;
    }
    if let Some(file) = &inner.fd_table[fd] {
        match file {
            FileClass::OSInode(inode) => {
                buf.read(inode.fstat().as_bytes());
                return 0;
            }
            _ => return -1,
        }
    } else {
        return -1;
    }
}

pub fn sys_pipe2(pipe: *mut u32) -> isize {
    let task = current_task().unwrap();
    let token = current_user_token();
    let mut inner = task.inner_exclusive_access();
    let (pipe_read, pipe_write) = make_pipe();
    let read_fd = inner.alloc_fd();
    inner.fd_table[read_fd] = Some(FileClass::Other(pipe_read));
    let write_fd = inner.alloc_fd();
    inner.fd_table[write_fd] = Some(FileClass::Other(pipe_write));
    *translated_refmut(token, pipe) = read_fd as u32;
    *translated_refmut(token, unsafe { pipe.add(1) }) = write_fd as u32;
    0
}

pub fn sys_dup(fd: usize) -> isize {
    let task = current_task().unwrap();
    let mut inner = task.inner_exclusive_access();
    if fd >= inner.fd_table.len() {
        return -1;
    }
    if inner.fd_table[fd].is_none() {
        return -1;
    }
    let new_fd = inner.alloc_fd();
    inner.fd_table[new_fd] = Some(inner.fd_table[fd].as_ref().unwrap().clone());
    new_fd as isize
}

pub fn sys_dup3(oldfd: usize, newfd: usize) -> isize {
    let task = current_task().unwrap();
    let mut inner = task.inner_exclusive_access();
    if oldfd == newfd {
        return oldfd as isize;
    }
    if oldfd >= inner.fd_table.len() {
        return -1;
    }
    if inner.fd_table[oldfd].is_none() {
        return -1;
    }
    while newfd > inner.fd_table.len() - 1 {
        inner.fd_table.push(None);
    }
    inner.fd_table[newfd] = Some(inner.fd_table[oldfd].as_ref().unwrap().clone());
    newfd as isize
}

