pub fn sys_nanosleep(req: *mut Timespec, _rem: *mut Timespec) -> isize {
    let token = current_user_token();
    let end_sec = get_time_s() + (*translated_refmut(token, req)).tv_sec as usize;
    let end_usec = get_time_us() + (*translated_refmut(token, req)).tv_usec as usize;
    loop {
        let cur_sec = get_time_s();
        let cur_usec = get_time_us();
