/// If there is not a child process whose pid is same as given, return -1.
/// Else if there is a child process but it is still running, return -2.
/// 暂不支持非阻塞
pub fn sys_wait4(pid: isize, wstatus: *mut i32, _option: usize) -> isize {
    loop {
        let task = current_task().unwrap();
        // find a child process

        // ---- access current PCB exclusively
        let mut inner = task.inner_exclusive_access();
        if !inner
            .children
            .iter()
            .any(|p| pid == -1 || pid as usize == p.getpid())
        {
            return -1;
            // ---- release current PCB
        }

        let pair = inner.children.iter().enumerate().find(|(_, p)| {
            // ++++ temporarily access child PCB exclusively
            p.inner_exclusive_access().is_zombie() && (pid == -1 || pid as usize == p.getpid())
            // ++++ release child PCB
        });

        // let current_pid = task.getpid();
        if let Some((idx, _)) = pair {
            // 当检测到引用计数不为 1 时需挂起等待
            if Arc::strong_count(&inner.children[idx]) != 1 {
                drop(inner);
                drop(task);
                // println!("wait4: suspend");
                // println!("wait4: current pid = {}, wait pid = {}", current_pid, pid);
                suspend_current_and_run_next();
                continue;
            }
            let child = inner.children.remove(idx);

            // confirm that child will be deallocated after being removed from children list
            // 在多核条件下，这里不能做出断言。
            // 由于待回收的子进程先改变状态再 drop 掉，但在改变状态后另一个运行父进程的核立马进行了
            // 对子进程的回收，此时子进程的引用计数还是2。
            assert_eq!(Arc::strong_count(&child), 1);

            let found_pid = child.getpid();
            // ++++ temporarily access child PCB exclusively
            let exit_code = child.inner_exclusive_access().exit_code;
            // ++++ release child PCB

            // C 中 #define WEXITSTATUS(s) (((s)>>8)&0xFF)
            // 因此这里 exit_code 需要左移 8 位
            if wstatus as usize != 0 {
                *translated_refmut(inner.memory_set.token(), wstatus) = exit_code << 8;
            }
            return found_pid as isize;
        } else {
            drop(inner);
            drop(task);
            suspend_current_and_run_next();
        }
        // ---- release current PCB automatically
    }
}

pub fn sys_brk(end_data: usize) -> isize {
    let task = current_task().unwrap();
    let mut inner = task.inner_exclusive_access();
    if end_data != 0 {
        inner.brk = end_data;
    }
    return inner.brk as isize;
}

