/// 向 inode 表插入结点
pub fn insert_inode_table(inode: Inode) -> Arc<RwLock<Inode>> {
    // println!("in insert_inode_table");
    let mut inode_table = INODE_TABLE.lock();
    for i in 0..inode_table.len() {
        if inode_table[i].is_some() {
            let tmp = Arc::clone(&inode_table[i].as_ref().unwrap());
            let read_tmp = tmp.read();
            // println!(
            //     "index = {}, source first cluste = {}, dst first cluster = {}",
            //     i,
            //     read_tmp.first_cluster(),
            //     inode.first_cluster()
            // );
            if read_tmp.first_cluster() == inode.first_cluster() {
                // println!("get from inode table: index = {}", i);
                return Arc::clone(&tmp);
            }
            drop(read_tmp);
        }
    }
    // let name = inode.name();
    let res = Arc::new(RwLock::new(inode));
    if let Some(num) = (0..inode_table.len()).find(|num| inode_table[*num].is_none()) {
        // println!("insert inode table: index = {}, name = {}", num, name);
        inode_table[num] = Some(Arc::clone(&res));
    } else {
        // println!(
        //     "insert inode table: index = {}, name = {}",
        //     inode_table.len(),
        //     name
        // );
        inode_table.push(Some(Arc::clone(&res)));
    }
    res
}

/// 向打开文件表插入结点
pub fn insert_file_table(readable: bool, writable: bool, inode: Inode) -> Arc<OSInode> {
    // println!("in insert_file_table");
    let mut file_table = FILE_TABLE.lock();
    let res = Arc::new(OSInode::new(readable, writable, insert_inode_table(inode)));
    if let Some(num) = (0..file_table.len()).find(|num| file_table[*num].is_none()) {
        file_table[num] = Some(Arc::clone(&res));
    } else {
        file_table.push(Some(Arc::clone(&res)));
    }
    res
}

/// 移除 inode 表不被使用的结点
pub fn remove_from_inode_table() {
    let mut inode_table = INODE_TABLE.lock();
    loop {
        let mut num = 0;
        while num < inode_table.len() {
            if inode_table[num].is_some()
                && Arc::strong_count(&inode_table[num].as_ref().unwrap()) == 1
            {
                // let tmp = Arc::clone(&inode_table[num].as_ref().unwrap());
                // println!(
                //     "in remove_from_inode_table: delete index = {}",
                //     tmp.read().name()
                // );
                // drop(tmp);
                inode_table.remove(num).unwrap();
                break;
            }
            num += 1;
        }
        if num == inode_table.len() {
            return;
        }
    }
}

/// 移除打开文件表不被使用的结点
pub fn remove_from_file_table() {
    let mut file_table = FILE_TABLE.lock();
    loop {
