pub const AT_FDCWD: isize = -100;

pub struct OSInode {
    readable: bool,
    writable: bool,
    inner: Mutex<OSInodeInner>,
}

pub struct OSInodeInner {
    offset: usize,
    pub inode: Arc<RwLock<Inode>>,
}

impl OSInode {
    pub fn inner_exclusive_access(&self) -> MutexGuard<'_, OSInodeInner> {
        self.inner.lock()
    }

    pub fn new(readable: bool, writable: bool, inode: Arc<RwLock<Inode>>) -> Self {
        Self {
            readable,
            writable,
            inner: Mutex::new(OSInodeInner { offset: 0, inode }),
        }
    }
    pub fn read_all(&self) -> Vec<u8> {
        let mut inner = self.inner_exclusive_access();
        let mut buffer = [0u8; 512];
        let mut v: Vec<u8> = Vec::new();
        loop {
            let len = inner.inode.read().read_at(inner.offset, &mut buffer);
            if len == 0 {
                break;
            }
            inner.offset += len;
            v.extend_from_slice(&buffer[..len]);
        }
        v
    }

    pub fn seek(&self, off: usize) {
        self.inner_exclusive_access().offset = off;
    }

    pub fn getdents64(&self) -> Dirent {
        let inner = self.inner_exclusive_access();
        let inode = inner.inode.read();
        Dirent::new(
            inode.name(),
            inode.first_cluster() as u64,
            inode.attribute().bits(),
        )
    }

    pub fn fstat(&self) -> Kstat {
        let inner = self.inner_exclusive_access();
        let inode = inner.inode.read();
        Kstat::new(3, inode.first_cluster() as u64, 0o664, inode.size() as i64)
    }

    /// 清空文件
    pub fn clear(&self) {
        self.inner_exclusive_access().inode.write().clear();
    }
}

impl File for OSInode {
    fn readable(&self) -> bool {
        self.readable
    }
    fn writable(&self) -> bool {
        self.writable
    }
    fn read(&self, mut buf: UserBuffer) -> usize {
        let mut inner = self.inner_exclusive_access();
        let mut total_read_size = 0usize;
        for slice in buf.buffers.iter_mut() {
            let read_size = inner.inode.read().read_at(inner.offset, *slice);
            if read_size == 0 {
                break;
            }
            inner.offset += read_size;
            total_read_size += read_size;
        }
        total_read_size
    }
    fn write(&self, buf: UserBuffer) -> usize {
        let mut inner = self.inner_exclusive_access();
        let mut total_write_size = 0usize;
        for slice in buf.buffers.iter() {
            let write_size = inner.inode.write().write_at(inner.offset, *slice);
            assert_eq!(write_size, slice.len());
            inner.offset += write_size;
            total_write_size += write_size;
        }
        total_write_size
    }
}

