/// 打开指定目录下的文件
///
/// 这里有许多加锁动作，且之后会对打开文件表、inode 表进行查找，
/// 查找时会遍历所有的结点，因此也有加锁动作，非常容易出现死锁，需要仔细考虑
pub fn open_file(dir: Arc<OSInode>, name: &str, flags: OpenFlags) -> Option<Arc<OSInode>> {
    // println!("in open_file");
    let dir = &dir.inner_exclusive_access().inode;
    let (readable, writable) = flags.read_write();
    if flags.contains(OpenFlags::CREATE) {
        let read_dir = dir.read();
        if let Some(inode) = read_dir.find_entry(name) {
            drop(read_dir);
            let res = insert_file_table(readable, writable, inode);
            // clear size
            res.clear();
            Some(res)
        } else {
            // create file
            drop(read_dir);
            let mut write_dir = dir.write();
            // create 检查文件不存在会返回 None，而这已经检查过了，可以直接 unwrap
            let res = write_dir.create(name, Attribute::ARCHIVE).unwrap();
            // 注意解锁以便可以遍历文件表
            drop(write_dir);
            Some(insert_file_table(readable, writable, res))
        }
    } else {
        dir.read().find_entry(name).map(|tmp| {
            let inode = insert_file_table(readable, writable, tmp);
            if flags.contains(OpenFlags::TRUNC) {
                inode.clear();
            }
            inode
        })
    }
}

/// 根据路径进行搜索，直到达到最顶层目录
///
/// 若为绝对路径，则从根节点开始查找</br>
/// 若为相对路径，且 fd = AT_FDCWD，则从当前工作目录开始查找</br>
/// 若为相对路径，且 fd 为一个合法文件描述符，则从指向的目录开始查找
///
/// 返回顶层目录的 osinode 结点，但该结点为临时结点，并不添加到 file_table 中
fn get_dir(fd: isize, path: &str) -> Option<Arc<OSInode>> {
    // println!("in get_dir");
    let task = current_task().unwrap();
    let inner = task.inner_exclusive_access();
    let relative_osinode;
    if path.starts_with('/') {
        relative_osinode = root_inode();
    } else {
        if fd == AT_FDCWD {
            relative_osinode = Arc::clone(&inner.cwd);
        } else {
            match inner.fd_table[fd as usize].as_ref().unwrap() {
                FileClass::OSInode(osinode) => relative_osinode = Arc::clone(&osinode),
                _ => return None,
            }
        }
    }

    let relative_inode = &relative_osinode.inner_exclusive_access().inode;
    let res = relative_inode
        .read()
        .get_dir(path)
        .map(|parent| Arc::new(OSInode::new(true, true, Arc::new(RwLock::new(parent)))));
    // println!("out get_dir");
    res
}

/// 根据路径打开文件
///
/// fd 意义与 get_dir 相同
pub fn open_file_at(fd: isize, path: &str, flags: OpenFlags) -> Option<Arc<OSInode>> {
    // println!("in open_file_at");
    match get_dir(fd, path) {
        Some(parent) => {
            match path
                .trim_end_matches('/')
                .split('/')
                .collect::<Vec<_>>()
                .pop()
            {
                Some(name) => open_file(parent, name, flags),
                None => None,
            }
        }
        None => None,
    }
}

/// 创建目录
///
/// 只创建目录文件，而不打开
pub fn mkdir_at(fd: isize, path: &str) -> isize {
    // println!("in mkdir_at");
    match get_dir(fd, path) {
        Some(parent) => {
            match path
                .trim_end_matches('/')
                .split('/')
                .collect::<Vec<_>>()
                .pop()
            {
                Some(name) => {
                    let parent = &parent.inner_exclusive_access().inode;
                    parent.write().create(name, Attribute::DIRECTORY);
                    // println!("out mkdir_at");
                    0
                }
                None => -1,
            }
        }
        None => -1,
    }
}

/// 移除指定文件的链接(可用于删除文件)
///
/// 目前实现仅能删除文件
pub fn unlinkat(fd: isize, path: &str) -> isize {
    if let Some(inode) = open_file_at(fd, path, OpenFlags::RDONLY) {
        inode.inner_exclusive_access().inode.write().remove();
        drop(inode);
        remove_from_file_table();
        0
    } else {
        -1
    }
}

