pub struct Dirent {
    pub d_ino: u64, // 索引结点号(第一个簇号)
    pub d_off: i64, // 64-bit offset to next structure

    // Size of this dirent，在 man 文档中，dirent 结构体中 d_name 大小是不确定的，没有规定 MAXNAME 的大小
    // 通过设置 null 来表示结尾，因此可能用该变量表示该结构体的大小
    pub d_reclen: u16,

    pub d_type: u8,            // 文件类型
    pub d_name: [u8; MAXNAME], // 文件名
}

impl Dirent {
    pub fn new(name: String, firstcluster: u64, attribute: u8) -> Self {
        Self {
            d_ino: firstcluster,
            d_off: core::mem::size_of::<Self>() as i64,
            d_reclen: name.len() as u16 + 19,
            d_type: attribute,
            d_name: {
                let mut tmp: [u8; MAXNAME] = [0; MAXNAME];
                tmp[..name.len()].copy_from_slice(name.as_bytes());
                tmp
            },
        }
    }

    pub fn as_bytes(&self) -> &[u8] {
        let size = core::mem::size_of::<Self>();
        unsafe { core::slice::from_raw_parts(self as *const _ as usize as *const u8, size) }
    }
}

