/// 由于 fsinfo 结构只保存 fsinfo 扇区地址，所有的操作都通过查找相应的块完成，
/// 因此可以不对 fsinfo 添加锁。
///
/// 而 fat 结构在操作时还经过一些其它处理计算，当 fat 没有加锁，
/// 只对块缓冲加锁并且其操作完成时，可能转到其它线程执行，
/// 此时会破坏已有的结构（如当前请求的块缓冲被使用而导致继续使用该块的结果进行计算
/// 而产生错误），因此对 fat 进行了加锁。
pub struct FAT32Manager {
    block_device: Arc<dyn BlockDevice>,
    fsinfo: Arc<FSInfo>,
    fat: Arc<RwLock<FAT>>,
    pub sectors_per_cluster: u32,
    pub bytes_per_sector: u32,
    pub bytes_per_cluster: u32,
    root_sec: u32, // 数据区的起始扇区
}

type DataBlock = [u8; BLOCK_SZ];

impl FAT32Manager {
    /* 某个簇的第一个扇区 */
    pub fn first_sector_of_cluster(&self, cluster: u32) -> usize {
        (cluster as usize - 2) * self.sectors_per_cluster as usize + self.root_sec as usize
    }

    /* 打开现有的FAT32  */
    pub fn open(block_device: Arc<dyn BlockDevice>) -> Arc<RwLock<Self>> {
        // 读入分区偏移
        println!("[fs]: Load FAT32");
        let start_sector: u32 =
            get_block_cache(0, Arc::clone(&block_device))
                .read()
                .read(0x1c6, |sector: &[u8; 4]| {
                    let mut start_sec: u32 = 0;
                    for i in 0..4 {
                        let tmp = sector[i] as u32;
                        start_sec = start_sec + (tmp << (8 * i));
                    }
                    start_sec
                });
        println!("[fs]: start sector = {}", start_sector);
        set_start_sec(start_sector as usize);

        // 读入 BPB
        let dbr = get_block_cache(0, Arc::clone(&block_device))
            .read()
            .read(0, |dbr: &DataBlock| *dbr);
        let bpb = BPB::new(&dbr);
        println!("[fs]: BPB = {:?}", bpb);

        // 读入 FSInfo
        let fsinfo = FSInfo::new(bpb.fsinfo_sector as u32);
        // 校验签名
        assert!(
            fsinfo.check_signature(Arc::clone(&block_device)),
            "Error loading fat32! Illegal signature"
        );
        println!(
            "[fs]: first free cluster = {}",
            fsinfo.read_first_free_cluster(block_device.clone())
        );

        let sectors_per_cluster = bpb.sectors_per_cluster as u32;
        let bytes_per_sector = bpb.bytes_per_sector as u32;
        let bytes_per_cluster = sectors_per_cluster * bytes_per_sector;

