type DataBlock = [u8; BLOCK_SZ];

/// 文件 inode 结点
///
/// 对于 fat32 文件系统，一个文件可以由簇号识别，对应文件的数据区。
/// 对于普通文件来说，可能需要更改文件大小、时间等信息，而这存储在目录项中。
/// 因此 inode 存储文件对应的目录项，同时保存父目录的首簇号以及该目录项在父目录的偏移，
/// 从而确定该目录项的位置，这样设计也是为了便于获得文件名以及文件路径。
///
/// 对于目录等文件来说，其可能对应几个目录项（目录文件本身目录项以及`.`, `..`目录项），
/// 因此不能通过扇区号和偏移量来区分文件，只能通过首簇号区分文件，所以在创建每个文件初始化
/// 时都分配一个簇的空间。
///
/// 对于根目录，其`dir_first_cluster = 0`，`dir_offset`没有意义
///
/// 对于目录项 short_dir_entry 的处理，由于所需更改的字段较少（目前只有 size 这一字段）且所占空间不大，
/// 将其复制到内存，并设置 dirt 位，只在必要的时候进行更新。
///
/// 虽然成员 fs 包含 fat 以及 block_device，但将其分离出来方便处理
#[derive(Clone)]
pub struct Inode {
    dir_first_cluster: u32,         // 文件父目录数据的首簇号
    dir_offset: usize,              // 文件短目录项在文件父目录数据区的偏移
    short_dir_entry: ShortDirEntry, // 文件短目录项
    dirt: bool,                     // 短目录项的脏位（判断短目录项是否有改变，而不是文件数据）
    fs: Arc<RwLock<FAT32Manager>>,
    fat: Arc<RwLock<FAT>>,
    block_device: Arc<dyn BlockDevice>,
}

impl Inode {
    /// 新建 inode 结点
    pub fn new(
        dir_first_cluster: u32,
        dir_offset: usize,
        short_dir_entry: ShortDirEntry,
        fs: Arc<RwLock<FAT32Manager>>,
        fat: Arc<RwLock<FAT>>,
        block_device: Arc<dyn BlockDevice>,
    ) -> Self {
        Self {
            dir_first_cluster,
            dir_offset,
            short_dir_entry,
            dirt: false,
            fs,
            fat,
            block_device,
        }
    }

    /// 判断文件是否为目录文件
    pub fn is_dir(&self) -> bool {
        self.short_dir_entry.is_dir()
    }

    /// 获取文件属性
    pub fn attribute(&self) -> Attribute {
        Attribute::from_bits(self.short_dir_entry.attribute).unwrap()
    }

    /// 读取可能的长文件目录项，返回长文件名以及第一个长文件目录项的偏移
    ///
    /// 由于存储方式可能不一样，不能直接根据文件名是长短文件名来判断
    fn get_long_name(&self, checksum: u8) -> (Option<String>, usize) {
        let fs = self.fs.read();
        let mut num = 1;
        let mut offset = self.dir_offset as isize;
        let mut entry = LongDirEntry::empty();
        let mut long_name = String::new();
        loop {
            offset -= DIRENT_SZ as isize;
            if offset < 0 {
                break;
            }
            let (_, sector, block_offset) = fs.get_pos(self.dir_first_cluster, offset as usize);
            get_block_cache(sector, Arc::clone(&self.block_device))
                .read()
                .read(block_offset, |tmp: &LongDirEntry| {
                    entry = *tmp;
                });
            if !entry.is_valid() || entry.checksum != checksum || (entry.order & (!0x40)) != num {
                break;
            }
            long_name += &entry.get_name_format();
            if (entry.order & 0x40) != 0 {
                return (Some(long_name), offset as usize);
            }
            num += 1;
        }
        (None, 0)
    }

    /// 获取文件名
    ///
    /// 有的目录项 (`.` `..`) 并不对应真正的文件名，需要读取文件真正位置的目录项
    pub fn name(&self) -> String {
        let fs = self.fs.read();

        // 读取真正的短文件目录项
        // 只有目录文件才可能出现
        let mut short_entry = self.short_dir_entry.clone();
        if self.attribute().contains(Attribute::DIRECTORY) {
            // 父目录首簇为0，说明当前文件是根文件
            if self.dir_first_cluster == 0 {
                return String::from("/");
            }

            let (_, sector, block_offset) = fs.get_pos(self.dir_first_cluster, self.dir_offset);
            get_block_cache(sector, Arc::clone(&self.block_device))
                .read()
                .read(block_offset, |tmp: &ShortDirEntry| {
                    short_entry = *tmp;
                });
        }

        if let (Some(long_name), _) = self.get_long_name(short_entry.checksum()) {
            long_name
        } else {
            short_entry.name()
        }
    }

    /// 获取文件大小
    pub fn size(&self) -> usize {
        if self.is_dir() {
            (self
                .fat
                .read()
                .count_claster_num(self.first_cluster(), Arc::clone(&self.block_device))
                * self.fs.read().bytes_per_cluster) as usize
        } else {
            self.short_dir_entry.size as usize
        }
    }

    /// 设置大小
    pub fn set_size(&mut self, size: usize) {
        if !self.is_dir() {
            self.short_dir_entry.set_size(size as u32);
            self.dirt = true;
        }
    }

    /// 获取文件数据区第一个簇号
    pub fn first_cluster(&self) -> u32 {
        self.short_dir_entry.first_cluster()
    }

    /// 设置首簇
    pub fn set_first_cluster(&mut self, cluster: u32) {
        self.short_dir_entry.set_first_cluster(cluster);
        self.dirt = true;
    }

    /// 扩容
    fn increase_size(&mut self, new_size: usize) {
        let fs = self.fs.read();
        let num = fs.cluster_num_needed(self.size(), new_size);
        if num != 0 {
            match fs.alloc_cluster(num as u32) {
                0 => {
                    panic!("no space!");
                }
                first_cluster => {
                    let old_first_cluster = self.first_cluster();
                    if old_first_cluster >= END_CLUSTER {
                        drop(fs);
                        self.set_first_cluster(first_cluster);
                        self.set_size(new_size);
                        return;
                    } else {
                        let fat = self.fat.write();
                        let old_final_cluster = fat
                            .get_final_cluster(old_first_cluster, Arc::clone(&self.block_device));
                        fat.set_next_cluster(
                            old_final_cluster,
                            first_cluster,
                            Arc::clone(&self.block_device),
                        );
                    }
                }
            }
        }
        drop(fs);
        self.set_size(new_size);
    }

    /// 分配连续的目录项空间，用来保证长短文件目录项相邻
    ///
    /// num: 目录项的个数</br>
    /// 返回分配的第一个目录项的偏移</br>
    /// 简化：直接从目录的最后位置进行查找扩容，而不从头查找是否有文件被删除从而空出空间
