use super::{get_block_cache, BlockDevice, BLOCK_SZ};
use alloc::sync::Arc;
use alloc::vec::Vec;

const LEAD_SIGNATURE: u32 = 0x41615252;
const SECOND_SIGNATURE: u32 = 0x61417272;
pub const FREE_CLUSTER: u32 = 0x00000000;
pub const END_CLUSTER: u32 = 0x0FFFFFF8;
pub const BAD_CLUSTER: u32 = 0x0FFFFFF7;
const FATENTRY_PER_SEC: u32 = BLOCK_SZ as u32 / 4;

type DataBlock = [u8; BLOCK_SZ];

#[repr(packed)]
#[derive(Clone, Copy, Debug)]
pub struct BPB {
    pub bytes_per_sector: u16,   // 每扇区字节数
    pub sectors_per_cluster: u8, // 每簇扇区数
    pub reserved_sectors: u16,   // 保留扇区数
    pub fats: u8,                // FAT 表数目
    pub total_sectors: u32,      // 总扇区数
    pub sectors_per_fat: u32,    // 一个 FAT 表扇区数
    pub root_clusters: u32,      // 第一个目录簇号
    pub fsinfo_sector: u16,      // fsinfo扇区的扇区号
}

impl BPB {
    pub fn new(dbr: &DataBlock) -> Self {
        unsafe {
            Self {
                bytes_per_sector: *(dbr.as_ptr().add(0xb) as *const u16),
                sectors_per_cluster: *(dbr.as_ptr().add(0xd)),
                reserved_sectors: *(dbr.as_ptr().add(0xe) as *const u16),
                fats: *(dbr.as_ptr().add(0x10)),
                total_sectors: *(dbr.as_ptr().add(0x20) as *const u32),
                sectors_per_fat: *(dbr.as_ptr().add(0x24) as *const u32),
                root_clusters: *(dbr.as_ptr().add(0x2c) as *const u32),
                fsinfo_sector: *(dbr.as_ptr().add(0x30) as *const u16),
            }
        }
    }

    pub fn bytes_per_cluster(&self) -> u32 {
        self.bytes_per_sector as u32 * self.sectors_per_cluster as u32
    }
}

// 该结构体不对Buffer作结构映射，仅保留位置信息
// 但是为其中信息的获取和修改提供了接口
pub struct FSInfo {
    sector_num: u32,
}

impl FSInfo {
    pub fn new(sector_num: u32) -> Self {
        Self { sector_num }
    }

    fn check_lead_signature(&self, block_device: Arc<dyn BlockDevice>) -> bool {
        get_block_cache(self.sector_num as usize, block_device)
            .read()
            .read(0, |&lead_sig: &u32| lead_sig == LEAD_SIGNATURE)
    }

    fn check_another_signature(&self, block_device: Arc<dyn BlockDevice>) -> bool {
        get_block_cache(self.sector_num as usize, block_device)
            .read()
            .read(484, |&sec_sig: &u32| sec_sig == SECOND_SIGNATURE)
    }

    /*对签名进行校验*/
    pub fn check_signature(&self, block_device: Arc<dyn BlockDevice>) -> bool {
        return self.check_lead_signature(block_device.clone())
            && self.check_another_signature(block_device.clone());
    }

    /*读取空闲簇数*/
    pub fn read_free_clusters(&self, block_device: Arc<dyn BlockDevice>) -> u32 {
        get_block_cache(self.sector_num as usize, block_device)
            .read()
            .read(488, |&free_cluster_count: &u32| free_cluster_count)
    }

    /*写空闲簇数*/
    pub fn write_free_clusters(&self, free_clusters: u32, block_device: Arc<dyn BlockDevice>) {
        get_block_cache(self.sector_num as usize, block_device)
            .write()
            .modify(488, |free_cluster_count: &mut u32| {
                *free_cluster_count = free_clusters;
            });
    }

    // 下一个可用簇号，通常设置为最后一个分配的簇号
    pub fn read_first_free_cluster(&self, block_device: Arc<dyn BlockDevice>) -> u32 {
        get_block_cache(self.sector_num as usize, block_device)
            .read()
            .read(492, |&start_cluster: &u32| start_cluster)
    }

    // 更新下一个可用簇号
    pub fn write_first_free_cluster(&self, start_cluster: u32, block_device: Arc<dyn BlockDevice>) {
        get_block_cache(self.sector_num as usize, block_device)
            .write()
            .modify(492, |start_clu: &mut u32| {
                *start_clu = start_cluster;
            });
    }
}

// 不使用第二个 FAT 表
#[derive(Clone, Copy)]
pub struct FAT {
    fat1_sector: u32, // FAT1起始扇区
    sectors: u32,     // 一个 FAT 表的大小
    entries: u32,     // 每扇区有多少个 FAT 表项
}

impl FAT {
    pub fn new(fat1_sector: u32, sectors: u32, entries: u32) -> Self {
        Self {
            fat1_sector,
            sectors,
            entries,
        }
    }

    /* 计算簇对应表项的位置：sector 和 offset */
    fn calculate_pos(&self, cluster: u32) -> (u32, u32) {
        let fat1_sec = self.fat1_sector + cluster / FATENTRY_PER_SEC;
        let offset = 4 * (cluster % FATENTRY_PER_SEC);
        (fat1_sec, offset)
    }

    // 搜索下一个可用簇
    // 找不到下一个可用簇则返回 0
    pub fn next_free_cluster(
        &self,
        current_cluster: u32,
        block_device: Arc<dyn BlockDevice>,
    ) -> u32 {
        let total_cluster = self.sectors * self.entries;
        let mut current_cluster = current_cluster + 1;
        for i in 0..total_cluster {
            current_cluster = (current_cluster + i) % total_cluster;
            if current_cluster == 0 || current_cluster == 1 {
                continue;
            }

            let (fat1_sec, offset) = self.calculate_pos(current_cluster);
            // 查看当前cluster的表项
            let entry_val = get_block_cache(fat1_sec as usize, block_device.clone())
                .read()
                .read(offset as usize, |&entry_val: &u32| entry_val);
            if entry_val == FREE_CLUSTER {
                return current_cluster & 0x0FFFFFFF;
            }
        }
        0
    }

    /// 查询当前簇的下一个簇
    /// 
    /// 失败返回 0
    pub fn get_next_cluster(&self, cluster: u32, block_device: Arc<dyn BlockDevice>) -> u32 {
        let (fat1_sec, offset) = self.calculate_pos(cluster);
        let fat1_rs = get_block_cache(fat1_sec as usize, block_device.clone())
            .read()
            .read(offset as usize, |&next_cluster: &u32| next_cluster);
        if fat1_rs == BAD_CLUSTER || fat1_rs >= END_CLUSTER {
            0
        } else {
            fat1_rs & 0x0FFFFFFF
        }
    }

    /* 设置当前簇的下一个簇 */
    pub fn set_next_cluster(
        &self,
        cluster: u32,
        next_cluster: u32,
        block_device: Arc<dyn BlockDevice>,
    ) {
        let (fat1_sec, offset) = self.calculate_pos(cluster);
        get_block_cache(fat1_sec as usize, block_device.clone())
            .write()
            .modify(offset as usize, |old_clu: &mut u32| {
                *old_clu = next_cluster;
            });
    }

    pub fn set_end(&self, cluster: u32, block_device: Arc<dyn BlockDevice>) {
        self.set_next_cluster(cluster, END_CLUSTER, block_device);
    }

    // 从 start_cluster 开始的第 index 个簇号
    // index = 1 表示下一个簇号
    // 失败返回 0
    pub fn get_cluster_at(
        &self,
        start_cluster: u32,
        index: u32,
        block_device: Arc<dyn BlockDevice>,
    ) -> u32 {
        let mut cluster = start_cluster;
        for _ in 0..index {
            cluster = self.get_next_cluster(cluster, block_device.clone());
            if cluster == 0 {
                break;
            }
        }
        cluster & 0x0FFFFFFF
    }

    /// 获得从 start_cluster（含）开始的所有簇链</br>
    /// 假定 start_cluster 始终有效
    pub fn get_all_clusters(
        &self,
        start_cluster: u32,
        block_device: Arc<dyn BlockDevice>,
    ) -> Vec<u32> {
        let mut curr_cluster = start_cluster;
        let mut v_cluster: Vec<u32> = Vec::new();
        if start_cluster >= END_CLUSTER {
            return v_cluster;    
        }
        loop {
            v_cluster.push(curr_cluster & 0x0FFFFFFF);
            let next_cluster = self.get_next_cluster(curr_cluster, block_device.clone());
            if next_cluster == 0 {
                return v_cluster;
            } else {
                curr_cluster = next_cluster;
            }
        }
    }

    pub fn get_final_cluster(&self, start_cluster: u32, block_device: Arc<dyn BlockDevice>) -> u32 {
        // 同样没有判断 start_cluster 的有效值
        self.get_all_clusters(start_cluster, block_device)
            .pop()
            .unwrap()
    }

    pub fn count_claster_num(&self, start_cluster: u32, block_device: Arc<dyn BlockDevice>) -> u32 {
        if start_cluster == 0 {
            return 0;
        }
        self.get_all_clusters(start_cluster, block_device).len() as u32
    }
}

use super::{BlockDevice, BLOCK_SZ};
use alloc::collections::VecDeque;
use alloc::sync::Arc;
use lazy_static::*;
use spin::{Mutex, RwLock};

pub struct BlockCache {
    cache: [u8; BLOCK_SZ],
    block_id: usize,
    block_device: Arc<dyn BlockDevice>,
    modified: bool,
}

impl BlockCache {
    /// Load a new BlockCache from disk.
    pub fn new(block_id: usize, block_device: Arc<dyn BlockDevice>) -> Self {
        let mut cache = [0u8; BLOCK_SZ];
        block_device.read_block(block_id, &mut cache);
        Self {
            cache,
            block_id,
            block_device,
            modified: false,
        }
    }

    fn addr_of_offset(&self, offset: usize) -> usize {
        &self.cache[offset] as *const _ as usize
    }

    pub fn get_ref<T>(&self, offset: usize) -> &T
    where
        T: Sized,
    {
        let type_size = core::mem::size_of::<T>();
        assert!(offset + type_size <= BLOCK_SZ);
        let addr = self.addr_of_offset(offset);
        unsafe { &*(addr as *const T) }
    }

    pub fn get_mut<T>(&mut self, offset: usize) -> &mut T
    where
        T: Sized,
    {
        let type_size = core::mem::size_of::<T>();
        assert!(offset + type_size <= BLOCK_SZ);
        self.modified = true;
        let addr = self.addr_of_offset(offset);
        unsafe { &mut *(addr as *mut T) }
    }

    pub fn read<T, V>(&self, offset: usize, f: impl FnOnce(&T) -> V) -> V {
        f(self.get_ref(offset))
    }

    pub fn modify<T, V>(&mut self, offset: usize, f: impl FnOnce(&mut T) -> V) -> V {
        f(self.get_mut(offset))
    }

    pub fn sync(&mut self) {
        if self.modified {
            self.modified = false;
            self.block_device.write_block(self.block_id, &self.cache);
        }
    }
}

impl Drop for BlockCache {
    fn drop(&mut self) {
        self.sync()
    }
}

const BLOCK_CACHE_SIZE: usize = 16;

pub struct BlockCacheManager {
    pub start_sec: usize,
    queue: VecDeque<(usize, Arc<RwLock<BlockCache>>)>,
}

impl BlockCacheManager {
    pub fn new() -> Self {
        Self {
            start_sec: 0,
            queue: VecDeque::new(),
        }
    }

    pub fn get_block_cache(
        &mut self,
        block_id: usize,
        block_device: Arc<dyn BlockDevice>,
    ) -> Arc<RwLock<BlockCache>> {
        if let Some(pair) = self.queue.iter().find(|pair| pair.0 == block_id) {
            Arc::clone(&pair.1)
        } else {
            // substitute
            if self.queue.len() == BLOCK_CACHE_SIZE {
                // from front to tail
                if let Some((idx, _)) = self
                    .queue
                    .iter()
                    .enumerate()
                    .find(|(_, pair)| Arc::strong_count(&pair.1) == 1)
                {
                    self.queue.drain(idx..=idx);
                } else {
                    panic!("Run out of BlockCache!");
                }
            }
            // load block into mem and push back
            let block_cache = Arc::new(RwLock::new(BlockCache::new(
                block_id,
                Arc::clone(&block_device),
            )));
            self.queue.push_back((block_id, Arc::clone(&block_cache)));
            block_cache
        }
    }
}

lazy_static! {
    pub static ref DATA_BLOCK_CACHE_MANAGER: Mutex<BlockCacheManager> =
        Mutex::new(BlockCacheManager::new());
}

pub fn get_block_cache(
    block_id: usize,
    block_device: Arc<dyn BlockDevice>,
) -> Arc<RwLock<BlockCache>> {
    let mut manager = DATA_BLOCK_CACHE_MANAGER.lock();
    let phy_blk_id = manager.start_sec + block_id;
    manager.get_block_cache(phy_blk_id, block_device)
}

pub fn block_cache_sync_all() {
    let manager = DATA_BLOCK_CACHE_MANAGER.lock();
    for (_, cache) in manager.queue.iter() {
        cache.write().sync();
    }
}

pub fn set_start_sec(start_sec: usize) {
    DATA_BLOCK_CACHE_MANAGER.lock().start_sec = start_sec;
}

